#include <vector>
#include <queue>
int bfs_shortest_path(int n, std::vector<std::vector<int>>& adj, int src, int dst) {
    std::vector<int> dist(n, -1);
    std::queue<int> q;
    dist[src] = 0; q.push(src);
    while (!q.empty()) {
        int u = q.front(); q.pop();
        if (u == dst) return dist[u];
        for (int v : adj[u]) if (dist[v] == -1) { dist[v] = dist[u]+1; q.push(v); }
    }
    return -1;
}

