from collections import deque

def bfs_shortest_path(n: int, adj: list, src: int, dst: int) -> int:
    dist = [-1] * n
    dist[src] = 0
    q = deque([src])
    while q:
        u = q.popleft()
        if u == dst: return dist[u]
        for v in adj[u]:
            if dist[v] == -1:
                dist[v] = dist[u] + 1
                q.append(v)
    return -1

